using System.ClientModel;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

// ── Configuration ──────────────────────────────────────────────────────────────
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL")   ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.ForegroundColor = ConsoleColor.Red;
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    Console.ResetColor();
    return 1;
}

// ── Tool instances ─────────────────────────────────────────────────────────────
var http        = new HttpClient();
var searchTool  = new WebSearchTool(http);
var noteService = new NoteService();

// Register every public tool method as an AIFunction
var tools = new AITool[]
{
    AIFunctionFactory.Create(searchTool.SearchWebAsync),
    AIFunctionFactory.Create(searchTool.FetchPageContentAsync),
    AIFunctionFactory.Create(noteService.SaveNote),
    AIFunctionFactory.Create(noteService.GetAllNotes),
    AIFunctionFactory.Create(noteService.GetNotesByTopic),
    AIFunctionFactory.Create(noteService.ClearNotes),
};

// ── Build chat client with automatic function invocation ───────────────────────
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(new ApiKeyCredential(apiKey))
            .GetChatClient(model)
            .AsIChatClient())
    .UseFunctionInvocation()
    .Build();

const string SystemPrompt = """
    You are a Research Agent. Your job is to thoroughly research a topic the user
    provides, then deliver a well-organized summary of your findings.

    Workflow:
    1. Break the topic into 2-4 sub-questions that cover the subject well.
    2. For each sub-question, use SearchWebAsync to find relevant information.
    3. Optionally use FetchPageContentAsync to read promising articles in full.
    4. Use SaveNote to record every important finding (facts, statistics, quotes).
    5. After you have gathered enough material, use GetAllNotes to review your notes.
    6. Produce a final, well-structured summary with:
       - An overview paragraph
       - Key findings organized by theme
       - A "Sources" section listing URLs

    Always cite your sources. Be thorough but concise.
    """;

// ── Interactive loop ───────────────────────────────────────────────────────────
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════════════════╗");
Console.WriteLine("║           🔍  AI Research Agent  🔍             ║");
Console.WriteLine("║  Enter a topic to research, or 'quit' to exit.  ║");
Console.WriteLine("╚══════════════════════════════════════════════════╝");
Console.ResetColor();

while (true)
{
    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Green;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, SystemPrompt),
        new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary:\n\n{topic}"),
    };

    var options = new ChatOptions { Tools = [.. tools] };

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"\nResearching \"{topic}\" — this may take a minute...\n");
    Console.ResetColor();

    try
    {
        var response = await client.GetResponseAsync(messages, options);

        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine("═══════════════════ Research Summary ═══════════════════");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.ForegroundColor = ConsoleColor.Yellow;
        Console.WriteLine("════════════════════════════════════════════════════════");
        Console.ResetColor();

        // Show tool usage stats
        var savedNotes = noteService.GetAllNotes();
        if (savedNotes.Count > 0)
        {
            Console.ForegroundColor = ConsoleColor.DarkGray;
            Console.WriteLine($"\n📝 {savedNotes.Count} note(s) collected during research.");
            Console.ResetColor();
        }

        noteService.ClearNotes();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.Error.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");
return 0;

