using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search functionality by querying DuckDuckGo's HTML endpoint
/// and extracting result snippets.
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _http;

    public WebSearchTool(HttpClient http) => _http = http;

    [Description("Searches the web for a given query and returns a list of result titles, URLs, and snippets.")]
    public async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (default 5)")] int maxResults = 5)
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";

        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

        using var response = await _http.SendAsync(request);
        response.EnsureSuccessStatusCode();

        var html = await response.Content.ReadAsStringAsync();
        return ParseResults(html, maxResults);
    }

    [Description("Fetches the text content of a web page at the given URL. " +
                 "Use this to read full articles found via SearchWebAsync.")]
    public async Task<string> FetchPageContentAsync(
        [Description("The URL of the page to fetch")] string url)
    {
        using var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.UserAgent.ParseAdd("ResearchAgent/1.0");

        using var response = await _http.SendAsync(request);
        response.EnsureSuccessStatusCode();

        var html = await response.Content.ReadAsStringAsync();

        // Strip HTML to plain text and truncate for context window safety
        var text = StripHtml(html);
        return text.Length > 8_000 ? text[..8_000] + "\n...[truncated]" : text;
    }

    private static List<SearchResult> ParseResults(string html, int max)
    {
        var results = new List<SearchResult>();

        // DuckDuckGo HTML results are in <a class="result__a"> with snippet in <a class="result__snippet">
        var linkMatches = ResultLinkRegex().Matches(html);
        var snippetMatches = SnippetRegex().Matches(html);

        for (var i = 0; i < Math.Min(linkMatches.Count, max); i++)
        {
            var href = WebUtility.HtmlDecode(linkMatches[i].Groups["url"].Value);
            var title = StripHtml(linkMatches[i].Groups["title"].Value).Trim();
            var snippet = i < snippetMatches.Count
                ? StripHtml(snippetMatches[i].Groups["text"].Value).Trim()
                : "";

            if (!string.IsNullOrWhiteSpace(title))
                results.Add(new SearchResult(title, href, snippet));
        }

        return results;
    }

    private static string StripHtml(string html)
    {
        var text = HtmlTagRegex().Replace(html, " ");
        text = WebUtility.HtmlDecode(text);
        return CollapseWhitespaceRegex().Replace(text, " ").Trim();
    }

    [GeneratedRegex("""<a[^>]+class="result__a"[^>]*href="(?<url>[^"]+)"[^>]*>(?<text>.*?)</a>""",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ResultLinkWithTextRegex();

    [GeneratedRegex("""<a[^>]+class="result__a"[^>]*href="(?<url>[^"]+)"[^>]*>(?<title>.*?)</a>""",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ResultLinkRegex();

    [GeneratedRegex("""<a[^>]+class="result__snippet"[^>]*>(?<text>.*?)</a>""",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex CollapseWhitespaceRegex();
}

public sealed record SearchResult(string Title, string Url, string Snippet);

